q11 AS (INSERT INTO questions ("topicId",type,body,difficulty,"displayOrder") SELECT tid,'multiple_choice','バスに23人乗っています。次の停留所で14人乗りました。バスには今何人いますか？',2,11 FROM topic RETURNING id),
