q10 AS (INSERT INTO questions ("topicId",type,body,difficulty,"displayOrder") SELECT tid,'multiple_choice','リボンが2本あります。1本は5cm8mm、もう1本は3cm4mmです。あわせて何cm何mmですか？',2,10 FROM topic RETURNING id),
