c8  AS (INSERT INTO question_choices ("questionId",body,"isCorrect","displayOrder") SELECT id,'1cm',false,1 FROM q8 UNION ALL SELECT id,'2cm',true,2 FROM q8 UNION ALL SELECT id,'5cm',false,3 FROM q8 UNION ALL SELECT id,'20cm',false,4 FROM q8),
