-- ===== 時刻と時間 =====
WITH topic AS (
  SELECT t.id AS tid FROM topics t JOIN subjects s ON s.id = t."subjectId"
  WHERE s.slug = 'elem-math' AND t.slug = 'time-basic'
),
q1  AS (INSERT INTO questions ("topicId",type,body,difficulty,"displayOrder") SELECT tid,'multiple_choice','時計の長い針が12、短い針が3をさしています。何時ですか？',2,1 FROM topic RETURNING id),
q2  AS (INSERT INTO questions ("topicId",type,body,difficulty,"displayOrder") SELECT tid,'multiple_choice','時計の長い針が6、短い針が8をさしています。何時何分ですか？',2,2 FROM topic RETURNING id),
q3  AS (INSERT INTO questions ("topicId",type,body,difficulty,"displayOrder") SELECT tid,'multiple_choice','時計の長い針が3、短い針が10をさしています。何時何分ですか？',2,3 FROM topic RETURNING id),
q4  AS (INSERT INTO questions ("topicId",type,body,difficulty,"displayOrder") SELECT tid,'multiple_choice','今は午前10時30分です。30分後は何時何分ですか？',2,4 FROM topic RETURNING id),
q5  AS (INSERT INTO questions ("topicId",type,body,difficulty,"displayOrder") SELECT tid,'multiple_choice','今は午後2時45分です。15分後は何時何分ですか？',2,5 FROM topic RETURNING id),
q6  AS (INSERT INTO questions ("topicId",type,body,difficulty,"displayOrder") SELECT tid,'multiple_choice','今は午前9時20分です。40分前は何時何分ですか？',2,6 FROM topic RETURNING id),
q7  AS (INSERT INTO questions ("topicId",type,body,difficulty,"displayOrder") SELECT tid,'multiple_choice','今は午後3時10分です。50分前は何時何分ですか？',3,7 FROM topic RETURNING id),
q8  AS (INSERT INTO questions ("topicId",type,body,difficulty,"displayOrder") SELECT tid,'multiple_choice','学校が午前8時30分に始まり、午後3時に終わります。何時間何分の授業ですか？',3,8 FROM topic RETURNING id),
q9  AS (INSERT INTO questions ("topicId",type,body,difficulty,"displayOrder") SELECT tid,'multiple_choice','映画が午後1時15分に始まり、午後3時15分に終わりました。映画は何時間でしたか？',2,9 FROM topic RETURNING id),
q10 AS (INSERT INTO questions ("topicId",type,body,difficulty,"displayOrder") SELECT tid,'multiple_choice','公園に午前10時に着いて、午前11時30分に帰りました。公園にいた時間は何時間何分ですか？',2,10 FROM topic RETURNING id),
c1  AS (INSERT INTO question_choices ("questionId",body,"isCorrect","displayOrder") SELECT id,'2時',false,1 FROM q1 UNION ALL SELECT id,'3時',true,2 FROM q1 UNION ALL SELECT id,'4時',false,3 FROM q1 UNION ALL SELECT id,'12時',false,4 FROM q1),
c2  AS (INSERT INTO question_choices ("questionId",body,"isCorrect","displayOrder") SELECT id,'8時3分',false,1 FROM q2 UNION ALL SELECT id,'8時30分',true,2 FROM q2 UNION ALL SELECT id,'6時8分',false,3 FROM q2 UNION ALL SELECT id,'8時6分',false,4 FROM q2),
c3  AS (INSERT INTO question_choices ("questionId",body,"isCorrect","displayOrder") SELECT id,'10時3分',false,1 FROM q3 UNION ALL SELECT id,'10時15分',true,2 FROM q3 UNION ALL SELECT id,'3時10分',false,3 FROM q3 UNION ALL SELECT id,'10時30分',false,4 FROM q3),
c4  AS (INSERT INTO question_choices ("questionId",body,"isCorrect","displayOrder") SELECT id,'10時50分',false,1 FROM q4 UNION ALL SELECT id,'11時0分',true,2 FROM q4 UNION ALL SELECT id,'11時30分',false,3 FROM q4 UNION ALL SELECT id,'10時0分',false,4 FROM q4),
c5  AS (INSERT INTO question_choices ("questionId",body,"isCorrect","displayOrder") SELECT id,'2時55分',false,1 FROM q5 UNION ALL SELECT id,'3時0分',true,2 FROM q5 UNION ALL SELECT id,'3時15分',false,3 FROM q5 UNION ALL SELECT id,'2時45分',false,4 FROM q5),
c6  AS (INSERT INTO question_choices ("questionId",body,"isCorrect","displayOrder") SELECT id,'8時30分',false,1 FROM q6 UNION ALL SELECT id,'8時40分',true,2 FROM q6 UNION ALL SELECT id,'9時0分',false,3 FROM q6 UNION ALL SELECT id,'8時20分',false,4 FROM q6),
c7  AS (INSERT INTO question_choices ("questionId",body,"isCorrect","displayOrder") SELECT id,'2時10分',false,1 FROM q7 UNION ALL SELECT id,'2時20分',true,2 FROM q7 UNION ALL SELECT id,'2時30分',false,3 FROM q7 UNION ALL SELECT id,'3時0分',false,4 FROM q7),
c8  AS (INSERT INTO question_choices ("questionId",body,"isCorrect","displayOrder") SELECT id,'5時間30分',false,1 FROM q8 UNION ALL SELECT id,'6時間30分',true,2 FROM q8 UNION ALL SELECT id,'7時間0分',false,3 FROM q8 UNION ALL SELECT id,'6時間0分',false,4 FROM q8),
c9  AS (INSERT INTO question_choices ("questionId",body,"isCorrect","displayOrder") SELECT id,'1時間',false,1 FROM q9 UNION ALL SELECT id,'2時間',true,2 FROM q9 UNION ALL SELECT id,'3時間',false,3 FROM q9 UNION ALL SELECT id,'1時間30分',false,4 FROM q9),
c10 AS (INSERT INTO question_choices ("questionId",body,"isCorrect","displayOrder") SELECT id,'1時間',false,1 FROM q10 UNION ALL SELECT id,'1時間30分',true,2 FROM q10 UNION ALL SELECT id,'2時間',false,3 FROM q10 UNION ALL SELECT id,'1時間20分',false,4 FROM q10),
s2  AS (INSERT INTO question_steps ("questionId","stepNumber",body) SELECT id,1,'長い針が6のとき→30分、短い針が8のとき→8時 → 8時30分です。' FROM q2),
s3  AS (INSERT INTO question_steps ("questionId","stepNumber",body) SELECT id,1,'長い針が3のとき→15分（3×5＝15）、短い針が10のとき→10時 → 10時15分です。' FROM q3),
s6  AS (INSERT INTO question_steps ("questionId","stepNumber",body) SELECT id,1,'9時20分から40分前 → 20分から引けないので、9時からさかのぼります。9時－40分＝8時20分→ ×。20分前が8時40分、さらに20分前で8時40分です。' FROM q6),
s8  AS (INSERT INTO question_steps ("questionId","stepNumber",body) SELECT id,1,'8時30分から3時まで: 8時30分→12時は3時間30分、12時→3時は3時間 → 合計6時間30分です。' FROM q8)
SELECT 'time-basic done';
